import React, { useState } from 'react';
import { useNavigate, Link } from 'react-router-dom';
import api from '../axios';

export default function Login() {
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [error, setError] = useState('');
  const navigate = useNavigate();

  async function handleSubmit(e) {
    e.preventDefault();
    try {
      const { data } = await api.post('/auth/login', { email, password });
      localStorage.setItem('token', data.token);
      navigate('/');
    } catch (err) {
      setError('Invalid credentials');
    }
  }

  return (
    <div className="max-w-md mx-auto">
      <div className="mb-6 text-center">
        <h1 className="text-3xl font-semibold tracking-tight">
          <span className="bg-gradient-to-r from-blue-600 via-indigo-600 to-fuchsia-600 bg-clip-text text-transparent">Welcome back</span>
        </h1>
        <p className="text-gray-600 mt-1">Sign in to manage your tasks</p>
      </div>

      <div className="relative overflow-hidden rounded-2xl border bg-white/70 backdrop-blur p-6 shadow-sm">
        <div className="absolute inset-0 pointer-events-none bg-gradient-to-br from-indigo-500/5 via-fuchsia-500/5 to-blue-500/5" />
        <div className="relative">
          {error && <div className="text-sm text-red-600 mb-3">{error}</div>}
          <form onSubmit={handleSubmit} className="grid gap-4">
            <div>
              <label className="block text-sm font-medium text-gray-700">Email</label>
              <input type="email" className="mt-1 w-full border rounded-lg px-3 py-2 focus:outline-none focus:ring-2 focus:ring-indigo-500" value={email} onChange={(e) => setEmail(e.target.value)} required />
            </div>
            <div>
              <label className="block text-sm font-medium text-gray-700">Password</label>
              <input type="password" className="mt-1 w-full border rounded-lg px-3 py-2 focus:outline-none focus:ring-2 focus:ring-indigo-500" value={password} onChange={(e) => setPassword(e.target.value)} required />
            </div>
            <button className="px-4 py-2 rounded-lg bg-gradient-to-r from-blue-600 to-indigo-600 text-white shadow hover:from-blue-700 hover:to-indigo-700">Login</button>
          </form>
          <div className="text-sm mt-4 text-gray-700">No account? <Link to="/register" className="text-indigo-600">Register</Link></div>
        </div>
      </div>
    </div>
  );
}
